Patch Set 27:

I changed the patch a little bit:

diff --git a/lustre/include/lustre_intent.h b/lustre/include/lustre_intent.h
index 76dcd88789..1c78627d8e 100644
--- a/lustre/include/lustre_intent.h
+++ b/lustre/include/lustre_intent.h
@@ -33,6 +33,8 @@
 #ifndef LUSTRE_INTENT_H
 #define LUSTRE_INTENT_H

+#include <lustre/lustre_idl.h>
+
 /* intent IT_XXX are defined in lustre/include/obd.h */

 struct lookup_intent {
@@ -65,4 +67,9 @@ static inline void it_clear_disposition(struct lookup_intent *it, int flag)
 	it->it_disposition &= ~flag;
 }

+static inline bool it_layout_change(struct lookup_intent *it)
+{
+        return it->it_op == IT_LAYOUT && (it->it_flags & FMODE_WRITE);
+}
+
 #endif
diff --git a/lustre/llite/file.c b/lustre/llite/file.c
index b1d596346f..5656041548 100644
--- a/lustre/llite/file.c
+++ b/lustre/llite/file.c
@@ -4182,9 +4182,14 @@ static int ll_layout_intent(struct inode *inode, struct layout_intent *intent)
 	memset(&it, 0, sizeof(it));
 	it.it_op = IT_LAYOUT;

-	LDLM_DEBUG_NOLOCK("%s: requeue layout lock for file "DFID"(%p)",
+	/* reuse it_flags for potential layout change */
+	it.it_flags = FMODE_READ;
+	if (intent->li_opc == LAYOUT_INTENT_WRITE)
+		it.it_flags = FMODE_WRITE;
+
+	LDLM_DEBUG_NOLOCK("%s: requeue layout lock for file "DFID"(%p) opc %d",
 			  ll_get_fsname(inode->i_sb, NULL, 0),
-			  PFID(&lli->lli_fid), inode);
+			  PFID(&lli->lli_fid), inode, intent->li_opc);

 	rc = md_intent_lock(sbi->ll_md_exp, op_data, &it, &req,
 			    &ll_md_blocking_ast, 0);
diff --git a/lustre/mdc/mdc_locks.c b/lustre/mdc/mdc_locks.c
index ad15029447..35b96ce928 100644
--- a/lustre/mdc/mdc_locks.c
+++ b/lustre/mdc/mdc_locks.c
@@ -497,10 +497,6 @@ static struct ptlrpc_request *mdc_intent_layout_pack(struct obd_export *exp,
 	LASSERT(op_data->op_data_size == sizeof(*layout));
 	memcpy(layout, op_data->op_data, sizeof(*layout));

-	if (layout->li_opc == LAYOUT_INTENT_WRITE ||
-	    layout->li_opc == LAYOUT_INTENT_TRUNC)
-		it->it_flags |= FMODE_WRITE;
-
 	req_capsule_set_size(&req->rq_pill, &RMF_DLM_LVB, RCL_SERVER,
 			     obd->u.cli.cl_default_mds_easize);
 	ptlrpc_request_set_replen(req);
diff --git a/lustre/obdclass/genops.c b/lustre/obdclass/genops.c
index d30ac0dc87..a16d11984f 100644
--- a/lustre/obdclass/genops.c
+++ b/lustre/obdclass/genops.c
@@ -2245,8 +2245,7 @@ __u16 obd_get_mod_rpc_slot(struct client_obd *cli, __u32 opc,
 	 */
 	if (it != NULL &&
 	    (it->it_op == IT_GETATTR || it->it_op == IT_LOOKUP ||
-	     it->it_op == IT_READDIR ||
-	     (it->it_op == IT_LAYOUT && !(it->it_flags & FMODE_WRITE))))
+	     it->it_op == IT_READDIR || !it_layout_change(it)))
 			return 0;

 	if (opc == MDS_CLOSE)
@@ -2294,8 +2293,7 @@ void obd_put_mod_rpc_slot(struct client_obd *cli, __u32 opc,

 	if (it != NULL &&
 	    (it->it_op == IT_GETATTR || it->it_op == IT_LOOKUP ||
-	     it->it_op == IT_READDIR ||
-	     (it->it_op == IT_LAYOUT && !(it->it_flags & FMODE_WRITE))))
+	     it->it_op == IT_READDIR || !it_layout_change(it)))
 		return;

 	if (opc == MDS_CLOSE)
